#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n,k; scanf("%d %d",&n,&k);
        int *a = (int*)malloc(n*sizeof(int));
        for(int i=0;i<n;++i) scanf("%d",&a[i]);
        if(n) k %= n; else k = 0;
        for(int i=0;i<n;++i){
            int idx = (k + i) % n;
            printf("%d", a[idx]);
            if(i+1<n) printf(" ");
        }
        printf("\n");
        free(a);
    }
    return 0;
}

